const { CallbackHandler } = require("langfuse-langchain");
const { ChatOpenAI } = require("@langchain/openai");

// Get connected model
const model = await this.getInputConnectionData("ai_languageModel", 0);
const modelName = model.model; // e.g., "google/gemini-2.0-flash-001:free"
const temperature = model.temperature || 0.7;

// Initialize Langfuse callback handler
const sessionId = $input.item.json.sessionId;
const langfuseHandler = new CallbackHandler({
  sessionId,
  publicKey: process.env.LANGFUSE_PUBLIC_KEY,
  secretKey: process.env.LANGFUSE_SECRET_KEY,
  baseUrl: process.env.LANGFUSE_BASEURL, // optional
});

// Initialize OpenRouter LLM
const llm = new ChatOpenAI({
  modelName: modelName,
  temperature: temperature,
  openAIApiKey: process.env.OPENROUTER_API_KEY, // Your OpenRouter API key
  configuration: {
    baseURL: "https://openrouter.ai/api/v1",
  },
  callbacks: [langfuseHandler],
});

return llm;

